/**
 * ScratchHub — «Мои Scratch-проекты».
 * Список проектов + кнопки «Новый», «Загрузить .sb3».
 * Открывается из sidebar для child role и из карточки ученика для teacher.
 */

import { useEffect, useRef, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import {
  fetchMyScratchProjects, createScratchProject, deleteScratchProject,
  type ScratchProjectDto,
} from '../api/scratchProjects'

export default function ScratchHub() {
  const navigate = useNavigate()
  const { toast, show } = useToast()
  const fileInputRef = useRef<HTMLInputElement>(null)

  const [projects, setProjects] = useState<ScratchProjectDto[]>([])
  const [loading, setLoading] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [newTitle, setNewTitle] = useState('')

  function refresh() {
    setLoading(true)
    fetchMyScratchProjects()
      .then(setProjects)
      .catch(() => show('Бэкенд не отвечает — список пуст', 'info'))
      .finally(() => setLoading(false))
  }

  useEffect(refresh, [])

  async function handleUpload(file: File) {
    if (file.size > 25 * 1024 * 1024) { show('Файл больше 25 MB', 'error'); return }
    if (!file.name.endsWith('.sb3')) { show('Нужен .sb3 файл', 'error'); return }
    const title = newTitle.trim() || file.name.replace(/\.sb3$/, '')
    setUploading(true)
    const fd = new FormData()
    fd.append('file', file)
    fd.append('title', title)
    try {
      await createScratchProject(fd)
      show('Проект загружен', 'success')
      setNewTitle('')
      if (fileInputRef.current) fileInputRef.current.value = ''
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setUploading(false)
    }
  }

  async function handleDelete(p: ScratchProjectDto) {
    if (!confirm(`Удалить «${p.title}»?`)) return
    try {
      await deleteScratchProject(p.id)
      show('Удалено', 'success')
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  return (
    <PlatformShell>
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover" style={{ background: 'linear-gradient(135deg, #FF9454 0%, #E8517B 100%)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>🎮</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.85)' }}>Творчество</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Мои Scratch-проекты</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* Action bar */}
        <div className="kb-card" style={{ padding: 20, display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-end' }}>
          <button className="kb-btn" style={{ background: '#FF9454', color: '#fff', fontWeight: 800, padding: '12px 22px', fontSize: 15 }}
            onClick={() => navigate('/scratch/edit')}>
            ➕ Новый проект
          </button>
          <div style={{ flex: 1, minWidth: 240 }}>
            <label style={lbl}>Загрузить .sb3 с компа</label>
            <div style={{ display: 'flex', gap: 8 }}>
              <input style={{ ...inp, flex: 1 }} placeholder="Название (необязательно)" value={newTitle} onChange={(e) => setNewTitle(e.target.value)} />
              <input ref={fileInputRef} type="file" accept=".sb3" style={{ display: 'none' }}
                onChange={(e) => { const f = e.target.files?.[0]; if (f) void handleUpload(f) }} />
              <button className="kb-btn" disabled={uploading} onClick={() => fileInputRef.current?.click()}>
                {uploading ? '…' : '📤 Выбрать файл'}
              </button>
            </div>
          </div>
        </div>

        {/* Projects grid */}
        {loading ? null : projects.length === 0 ? (
          <div className="kb-card" style={{ padding: 40, textAlign: 'center' }}>
            <div style={{ fontSize: 56, marginBottom: 12 }}>🐱</div>
            <h3 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Проектов пока нет</h3>
            <p style={{ marginTop: 8, fontSize: 14, color: 'var(--ink-soft)' }}>
              Нажми «Новый проект» — откроется редактор, где можно перетаскивать блоки и собирать игры.
            </p>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 16 }}>
            {projects.map((p) => (
              <div key={p.id} className="kb-card" style={{ padding: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                <Link to={`/scratch/play/${p.id}`} style={{
                  display: 'block', height: 160, background: p.thumbnailUrl ? `url(${p.thumbnailUrl}) center/cover` : 'linear-gradient(135deg, #FFD43C, #FF9454)',
                  position: 'relative',
                }}>
                  {!p.thumbnailUrl && <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60 }}>🎮</div>}
                </Link>
                <div style={{ padding: 14, flex: 1, display: 'flex', flexDirection: 'column' }}>
                  <h4 style={{ margin: 0, fontSize: 15, fontWeight: 800 }}>{p.title}</h4>
                  <div style={{ marginTop: 4, fontSize: 11, color: 'var(--ink-soft)' }}>
                    {(p.sizeBytes / 1024).toFixed(0)} KB · {p.viewCount} просм.
                  </div>
                  {p.submittedAt && (
                    <div style={{ marginTop: 6, fontSize: 11, color: '#059669', fontWeight: 700 }}>
                      ✓ Сдан учителю
                    </div>
                  )}
                  {p.gradedAt && (
                    <div style={{ marginTop: 6, fontSize: 12, fontWeight: 700, color: 'var(--violet)' }}>
                      Оценка: {'⭐'.repeat(p.grade ?? 0)}
                    </div>
                  )}
                  <div style={{ marginTop: 'auto', paddingTop: 10, display: 'flex', gap: 6 }}>
                    <Link to={`/scratch/edit/${p.id}`} className="kb-btn" style={{ flex: 1, fontSize: 12, padding: '6px 10px', textAlign: 'center', textDecoration: 'none' }}>
                      ✏️ Редактировать
                    </Link>
                    <button className="kb-btn" style={{ fontSize: 12, padding: '6px 10px', background: '#dc2626', color: '#fff' }} onClick={() => void handleDelete(p)}>
                      ×
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </PlatformShell>
  )
}

const lbl: React.CSSProperties = { display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase', color: 'var(--ink-soft)', marginBottom: 4 }
const inp: React.CSSProperties = { width: '100%', padding: '8px 12px', borderRadius: 8, border: '1px solid var(--paper-3)', fontSize: 13, fontFamily: 'inherit', boxSizing: 'border-box' }
